def rle_encode(s):
    if not s:
        return ''
    out, prev, count = [], s[0], 1
    for ch in s[1:]:
        if ch == prev:
            count += 1
        else:
            out.append(f'{prev}{count}')
            prev, count = ch, 1
    out.append(f'{prev}{count}')
    return ''.join(out)

def is_balanced(s):
    pairs = {')': '(', ']': '[', '}': '{'}
    stack = []
    for ch in s:
        if ch in '([{':
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return False
    return not stack

def compare_semver(a, b):
    ta = tuple(int(x) for x in a.split('.'))
    tb = tuple(int(x) for x in b.split('.'))
    return (ta > tb) - (ta < tb)

