def flatten_dict(d, prefix=''):
    out = {}
    for k, v in d.items():
        key = f'{prefix}.{k}' if prefix else str(k)
        if isinstance(v, dict) and v:
            out.update(flatten_dict(v, key))
        else:
            out[key] = v
    return out

